import React, { useMemo, useState } from "react";
import { Download, Link as LinkIcon, ListChecks, IdCard, FileSpreadsheet } from "lucide-react";
import * as XLSX from "xlsx";

// Ekranda ve Excel şablonunda kullanılacak başlıklar
const HEADERS = [
    "Müşteri VKN",
    "Müşteri Unvan",
    "Hizmet Tipi",
    "Proje Adı",
    "Sipariş Tarihi",
    "Yükleme Tarihi",
    "Teslim Tarihi",
    "Müşteri Siparis No",
    "Müşteri Referans No",
    "İstenilen Araç Tipi",
    "Açıklama",
    "Yükleme Noktası",
    "Yükleme İli",
    "Yükleme İlçesi",
    "Yükleme Yeri",
    "Alıcı Firma",
    "Teslim Noktası",
    "Teslim İli",
    "Teslim İlçesi",
    "Teslim Yeri",
    "İrsaliye No",
    "İrsaliye Miktar",
    "Ürün",
    "Kap Adet",
    "Ambalaj Tipi",
    "Brüt KG",
    "M3",
    "Desi",
];

const emptyRow = () => HEADERS.reduce((acc, key) => ({ ...acc, [key]: "" }), {});

export default function SiparisOlustur() {
    const [projeAdi, setProjeAdi] = useState("");
    const [rows, setRows] = useState([emptyRow()]);

    const columns = useMemo(() => HEADERS, []);

    const handleTemplateDownload = () => {
        // Sadece başlıklar ve tek boş satırla Excel şablonu indir
        const wsData = [columns, ...[emptyRow()].map((r) => columns.map((c) => r[c] ?? ""))];
        const ws = XLSX.utils.aoa_to_sheet(wsData);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Sablon");
        XLSX.writeFile(wb, `Siparis_Sablon_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    const handleExportExcel = () => {
        // Ekrandaki tabloyu Excel'e aktar
        const data = rows.map((r) => {
            const obj = {};
            columns.forEach((c) => (obj[c] = r[c] ?? ""));
            return obj;
        });
        const ws = XLSX.utils.json_to_sheet(data, { header: columns });
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Siparisler");
        XLSX.writeFile(wb, `Siparisler_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    const handleEslesmeYap = () => {
        alert("Eşleşme işlemi örnek olarak tetiklendi. Buraya API çağrınızı bağlayabilirsiniz.");
    };

    const handleEslesmeIdGetir = () => {
        // Örnek demo: sahte ID üretimi
        const fakeId = Math.random().toString(36).slice(2, 10).toUpperCase();
        alert(`Eşleşme ID'si: ${fakeId}\n(Not: Buraya servis entegrasyonu eklenecek.)`);
    };

    const addRow = () => setRows((r) => [...r, emptyRow()]);
    const removeRow = (idx) => setRows((r) => r.filter((_, i) => i !== idx));
    const updateCell = (idx, key, value) =>
        setRows((r) => r.map((row, i) => (i === idx ? { ...row, [key]: value } : row)));

    return (
        <div className="w-full max-w-[95rem] mx-auto p-6">
            {/* Başlık */}
            <div className="mb-6 flex items-center justify-between">
                <h1 className="text-2xl font-semibold tracking-tight">Sipariş Oluştur</h1>
                <div className="text-sm text-gray-500">SiparisOlustur.js</div>
            </div>

            {/* Üst Aksiyonlar */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 mb-6">
                <div className="p-4 rounded-2xl border shadow-sm bg-white">
                    <label className="block text-sm font-medium mb-2">Proje Adı</label>
                    <select
                        className="w-full rounded-xl border px-3 py-2 focus:outline-none focus:ring"
                        value={projeAdi}
                        onChange={(e) => setProjeAdi(e.target.value)}
                    >
                        <option value="">Seçiniz</option>
                        <option>Proje A</option>
                        <option>Proje B</option>
                        <option>Proje C</option>
                    </select>
                    <p className="mt-2 text-xs text-gray-500">Projeyi seçtiğinizde tablo satırlarında "Proje Adı" alanı hızlı doldurulur.</p>
                </div>

                <div className="p-4 rounded-2xl border shadow-sm bg-white flex flex-col gap-3">
                    <button
                        onClick={handleTemplateDownload}
                        className="inline-flex items-center gap-2 rounded-xl border px-4 py-2 hover:bg-gray-50"
                    >
                        <Download size={18} /> Şablonu İndir
                    </button>
                    <button
                        onClick={handleEslesmeYap}
                        className="inline-flex items-center gap-2 rounded-xl border px-4 py-2 hover:bg-gray-50"
                    >
                        <LinkIcon size={18} /> Eşleşme Yap
                    </button>
                    <button
                        onClick={handleEslesmeIdGetir}
                        className="inline-flex items-center gap-2 rounded-xl border px-4 py-2 hover:bg-gray-50"
                    >
                        <IdCard size={18} /> Eşleşme ID'lerini Getir
                    </button>
                    <button
                        onClick={handleExportExcel}
                        className="inline-flex items-center gap-2 rounded-xl border px-4 py-2 hover:bg-gray-50"
                    >
                        <FileSpreadsheet size={18} /> Dışarı Excel Aktarma
                    </button>
                </div>

                <div className="p-4 rounded-2xl border shadow-sm bg-white">
                    <div className="flex items-center gap-3">
                        <button
                            onClick={addRow}
                            className="rounded-xl border px-4 py-2 hover:bg-gray-50"
                        >
                            Satır Ekle
                        </button>
                        <button
                            onClick={() => setRows([emptyRow()])}
                            className="rounded-xl border px-4 py-2 hover:bg-gray-50"
                        >
                            Şablonu Sıfırla
                        </button>
                    </div>
                    <p className="mt-2 text-xs text-gray-500">Tabloda satır ekleyebilir ya da şablonu başlangıç haline döndürebilirsiniz.</p>
                </div>
            </div>

            {/* Şablon Tablosu */}
            <div className="rounded-2xl border shadow-sm overflow-x-auto bg-white">
                <div className="p-4 border-b flex items-center gap-2">
                    <ListChecks size={18} />
                    <span className="font-medium">Şablon</span>
                    <span className="text-xs text-gray-500">(Şablon İndir ile aynı başlıklara sahiptir)</span>
                </div>

                <table className="min-w-[1200px] w-full text-sm">
                    <thead className="bg-gray-50">
                        <tr>
                            <th className="sticky left-0 bg-gray-50 z-10 px-3 py-2 text-left border-b">#</th>
                            {columns.map((col) => (
                                <th key={col} className="px-3 py-2 text-left border-b whitespace-nowrap">
                                    {col}
                                </th>
                            ))}
                            <th className="px-3 py-2 text-left border-b">İşlem</th>
                        </tr>
                    </thead>
                    <tbody>
                        {rows.map((row, rowIdx) => (
                            <tr key={rowIdx} className="odd:bg-white even:bg-gray-50">
                                <td className="sticky left-0 bg-white/90 backdrop-blur z-10 px-3 py-2 border-b">{rowIdx + 1}</td>
                                {columns.map((col) => (
                                    <td key={`${rowIdx}-${col}`} className="px-3 py-1.5 border-b">
                                        <input
                                            className="w-full rounded-lg border px-2 py-1 text-sm focus:outline-none focus:ring"
                                            value={
                                                col === "Proje Adı" && !row[col] && projeAdi ? projeAdi : row[col]
                                            }
                                            onChange={(e) => updateCell(rowIdx, col, e.target.value)}
                                            placeholder={col}
                                        />
                                    </td>
                                ))}
                                <td className="px-3 py-2 border-b">
                                    <button
                                        onClick={() => removeRow(rowIdx)}
                                        className="rounded-lg border px-3 py-1 hover:bg-gray-50"
                                    >
                                        Sil
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            <div className="mt-4 text-xs text-gray-500">
                İpucu: "Şablonu İndir" butonu ile indirilen Excel dosyasının başlıkları, bu tabloda gördüklerinizle birebir aynıdır.
            </div>
        </div>
    );
}
